import React, { useEffect, useState } from "react";
import axios from "axios";


const API_BASE = "http://localhost:5000/api/products";

const blankForm = {
  name: "",
  description: "",
  category: "Earphone",
  price: "",
  offerPrice: "",
  image: "",
  purchaseYear: "",
  warranty: "",
  rating: ""
};

function SellerDashboard() {
  const [products, setProducts] = useState([]);
  const [form, setForm] = useState(blankForm);
  const [editingProduct, setEditingProduct] = useState(null);

  const savedTab = localStorage.getItem("activePage") || "list";
  const [activePage, setActivePage] = useState(savedTab);

  useEffect(() => { localStorage.setItem("activePage", activePage); }, [activePage]);
  useEffect(() => { fetchProducts(); }, []);

  const fetchProducts = async () => {
    try {
      const res = await axios.get(API_BASE);
      setProducts(res.data);
    } catch (err) {
      alert("Failed to load products");
    }
  };

  const handleChange = (e) => { setForm({ ...form, [e.target.name]: e.target.value }); };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editingProduct) {
        const res = await axios.put(`${API_BASE}/${editingProduct._id}`, form);
        setProducts((prev) => prev.map((p) => (p._id === res.data._id ? res.data : p)));
        alert("Updated");
      } else {
        const res = await axios.post(API_BASE, form);
        setProducts((prev) => [res.data, ...prev]);
        alert("Added");
      }
      setForm(blankForm);
      setEditingProduct(null);
      setActivePage("list");
    } catch {
      alert("Failed");
    }
  };

  const handleEdit = (product) => {
    setEditingProduct(product);
    setForm(product);
    setActivePage("add");
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Delete this product?")) return;
    await axios.delete(`${API_BASE}/${id}`);
    setProducts((prev) => prev.filter((p) => p._id !== id));
  };

  return (
    <div className="seller-dashboard-container">

      <aside className="seller-sidebar">
        <h2>Seller Panel</h2>
        <ul>
          <li className={activePage === "add" ? "active" : ""} onClick={() => { setActivePage("add"); setEditingProduct(null); setForm(blankForm); }}>➕ Add Product</li>
          <li className={activePage === "list" ? "active" : ""} onClick={() => setActivePage("list")}>📦 Product List</li>
          <li>📝 Orders</li>
        </ul>
      </aside>

      <main className="seller-main">

        {activePage === "add" && (
          <form onSubmit={handleSubmit} className="seller-card form-card">
            <h3>{editingProduct ? "Edit Product" : "Add Product"}</h3>

            <input type="text" name="name" placeholder="Product Name" value={form.name} onChange={handleChange} required />
            <textarea name="description" placeholder="Description" value={form.description} onChange={handleChange} />
            <select name="category" value={form.category} onChange={handleChange}>
              <option>Earphone</option>
              <option>Smartphone</option>
              <option>Laptop</option>
              <option>Smartwatch</option>
              <option>Other</option>
            </select>

            <input type="number" name="price" placeholder="Price" value={form.price} onChange={handleChange} required />
            <input type="number" name="offerPrice" placeholder="Offer Price" value={form.offerPrice} onChange={handleChange} />
            <input type="number" name="rating" placeholder="Rating (1-5)" value={form.rating} onChange={handleChange} />

            <input type="text" name="image" placeholder="Image URL" value={form.image} onChange={handleChange} required />
            {form.image && <img src={form.image} alt="" className="preview-img" />}

            <input type="number" name="purchaseYear" placeholder="Purchase Year" value={form.purchaseYear} onChange={handleChange} />
            <input type="text" name="warranty" placeholder="Warranty" value={form.warranty} onChange={handleChange} />

            <div className="btn-row">
              <button type="submit">{editingProduct ? "Update" : "Add"}</button>
              {editingProduct && <button type="button" onClick={() => { setEditingProduct(null); setForm(blankForm); }} className="cancel-btn">Cancel</button>}
            </div>
          </form>
        )}

        {activePage === "list" && (
          <div className="seller-card">
            <h3>Your Products</h3>
            <ul className="product-grid">
              {products.map((p) => (
                <li key={p._id} className="product-item-card">
                  <img src={p.image} alt="" />
                  <div>
                    <h4>{p.name}</h4>
                    <p>₹{p.price}</p>
                    {p.offerPrice && <p>Offer: ₹{p.offerPrice}</p>}
                    <small>Category: {p.category}</small><br />
                    <small>Year: {p.purchaseYear}</small><br />
                    <small>Warranty: {p.warranty}</small><br />
                    <small>Rating: {p.rating}</small>
                  </div>

                  <div className="actions">
                    <button onClick={() => handleEdit(p)}>Edit</button>
                    <button onClick={() => handleDelete(p._id)} className="del-btn">Delete</button>
                  </div>
                </li>
              ))}
            </ul>
          </div>
        )}
      </main>

    </div>
  );
}

export default SellerDashboard;
